import searchEmployees from '@salesforce/apex/EmployeeSearchController.searchEmployees';

export default class EmployeeSearch extends LightningElement {
    @track searchText = '';
    @track employees = [];
    @track isError = false;
    @track errorMessage = '';
    @track hasSearched = false;

    columns = [
        { label: 'Employee Name', fieldName: 'Name', type: 'text', sortable: true },
        { label: 'Employee ID', fieldName: 'Employee_ID__c', type: 'text', sortable: true },
        { label: 'Department', fieldName: 'Department__c', type: 'text', sortable: true },
        { label: 'Email', fieldName: 'Email__c', type: 'email', sortable: true }
    ];

    get hasResults() {
        return this.employees && this.employees.length > 0;
    }

    handleSearchTextChange(event) {
        this.searchText = event.target.value;
    }

    handleSearch() {
        this.isError = false;
        this.errorMessage = '';
        this.hasSearched = false;
        this.employees = [];

        if (!this.searchText || this.searchText.trim() === '') {
            this.isError = true;
            this.errorMessage = 'Please enter an employee name to search.';
            return;
        }

        searchEmployees({ searchText: this.searchText.trim() })
            .then(result => {
                this.employees = result;
                this.hasSearched = true;
                this.isError = false;
            })
            .catch(error => {
                this.isError = true;
                this.hasSearched = true;
                this.employees = [];
                this.errorMessage = error && error.body && error.body.message
                    ? error.body.message
                    : 'An unexpected error occurred while searching employees.';
            });
    }
}"}},{"num":4,"title":"Create LWC Meta XML: employeeSearch","type":"ApexClass","fullName":"employeeSearch/employeeSearch.js-meta.xml","detail":"Create the metadata configuration file for the employeeSearch LWC. Sets the API version to 59.0, marks the component as exposed, and configures it to be available in Lightning App Builder (AppPage), Record Pages (RecordPage), and Home pages (HomePage) so it can be added via drag-and-drop in the App Builder.","api":"Metadata API · LightningComponentBundle","action":"create","metadata":{"fullName":"employeeSearch","type":"LWC_META","body":"<?xml version="1.0" encoding="UTF-8"?>
